INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_dc44073fb75a', '专利代理实务真题2010.pdf', 58, '# 思博知网® MYSIPO

第二题评分标准 A（满分 60 分）

<table><tr><td>参考答案</td><td>分值</td><td>有关说明</td></tr><tr><td>一、简述审查指南中关于确定最接近的现有技术需要考虑的因素</td><td></td><td></td></tr><tr><td>最接近的现有技术,是指现有技术中与要求保护的发明最密切相关的一个技术方案,它是判断发明是否具有突出的实质性特点的基础。</td><td>2</td><td>【概念】=2分</td></tr><tr><td>最接近的现有技术,例如可以是,与要求保护的发明技术领域相同,所要解决的技术问题、技术效果或者用途最接近和/或公开了发明的技术特征最多的现有技术。</td><td>2</td><td></td></tr><tr><td>或者,虽然与要求保护的发明技术领域不同,但能够实现发明的功能,并且公开了发明的技术特征最多的现有技术。</td><td>1</td><td></td></tr><tr><td>应当注意的是,在确定最接近的现有技术时,应当首先考虑技术领域相同或相近似的现有技术。</td><td>2</td><td></td></tr><tr><td>二、确定附件2、附件3中哪一篇是本申请最接近的现有技术</td><td></td><td></td></tr><tr><td>附件2的技术领域与本申请相同,都是用于日常生活的食品加工领域,并且公开的特征也最多。附件3属于工业领域,技术领域与本申请不同,因此,附件2应为最接近的现有技术。</td><td>111</td><td>(1)附件编号错误,但从其答题内容的上下文可以看出对事实的认识是对的,正常得分。在整体表述部分酌情减分。</td></tr><tr><td>三、说明所撰写的权利要求书相对于现有技术具备新颖性和创造性的理由</td><td></td><td></td></tr><tr><td>1、权利要求1的新颖性</td><td></td><td></td></tr><tr><td>权利要求1与附件2相比:</td><td>2</td><td rowspan="3">[单独对比原则]=2分(1)只要找出一个区别技术特征就可得2分,例如"U型</td></tr><tr><td rowspan="2">(1)引流罩和内桶的结构不同,(2)引流罩和内桶的作用不同,(3)省掉了附件2技术方案中的“虑罩”,因此,区别特征在于引流罩,引流罩的下部为开口,并且引流罩上设置有引流孔,因此,权利要求1相对于附件2具备新颖性。</td><td>2</td></tr><tr><td>1</td></tr><tr><td></td><td></td><td>管状的加热器"(2)区别技术特征认定最多给2分(3)区别特征中引流罩的形状表述成"为上下开口的中空筒状"亦可。[结论]=1分</td></tr><tr><td>权利要求1与附件3相比(1)领域不同(2)解决的技术问题/作用不同,(3)液体流动方式不同,区别特征在于引流罩,引流罩为上下开口的中空筒状,并且引流罩上设置有引流孔。</td><td>2</td><td>(1)只要找出一个区别技术特征即可得2分,例如“U型管状的电热器”(2)区别技术特征认定最多给2分。</td></tr><tr><td>因此权利要求1相对于附件3具备新颖性。</td><td>1</td><td>[结论]=1分</td></tr><tr><td>2. 权利要求1的创造性</td><td></td><td></td></tr><tr><td>权利要求1与最接近的现有技术附件2的区别在于:食品料理机还包括一个引流罩,引流罩的下部为开口,并且引流罩上设置有引流孔。</td><td>2</td><td>(1)区别特征中引流罩的形状表述成"为上下开口的中空筒状"亦可。</td></tr><tr><td>该特征解决的技术问题为:通过设置引流罩,使得豆浆机更易清洗,同时,省掉了传统的“滤罩”使得本申请的制浆物料在桶体和引流罩内随水在大范围内循环粉碎制浆,粉碎制浆效果更好,制浆物料的营养析出更充分。</td><td>1</td><td></td></tr><tr><td>附件2中既没有公开该技术特征也没有给出任何技术启示,无法解决上述技术问题。</td><td>2</td><td></td></tr><tr><td>而附件3所涉及的技术领域、解决的技术问题,以及液体流动的方式均与本申请完全不同。</td><td>3</td><td></td></tr><tr><td>附件3公开的推进式搅拌器并未给出获得与“引流罩”相关的上述区别特征的技术启示。</td><td>1</td><td></td></tr><tr><td>而上述区别特征也不属于所属技术领域的惯用手段,</td><td>1</td><td></td></tr><tr><td>因此权利要求1相对于附件2、3及其结合,具有突出的实质性特点和显著的进步,具有专利法第22条第3款规定的创造性。</td><td>11</td><td>【结论】=2分</td></tr><tr><td>3、从属权利要求2-6的新颖性、创造性</td><td></td><td></td></tr><tr><td>由于权利要求1具备新颖性,其从属权利要求2-6也具备新颖性,</td><td>2</td><td></td></tr><tr><td>由于权利要求1具备创造性,其从属权利要求2-6也具备创造性。</td><td>2</td><td></td></tr><tr><td>4、权利要求7、8的新颖性、创造性</td><td></td><td></td></tr><tr><td>区别技术特征“引流罩上设置有引流孔”</td><td>1</td><td rowspan="6">注:权利要求7的区别技术特征如果写成其他特征,也可得区别技术特征的分、新颖性的分,但创造性的无启示的分不得。</td></tr><tr><td>新颖性单独对比</td><td>2</td></tr><tr><td>具有新颖性结论</td><td>1</td></tr><tr><td>附件2、3未公开区别技术特征并且无启示</td><td>2</td></tr><tr><td>权利要求7具备创造性的结论</td><td>1</td></tr><tr><td>由于权利要求7具备新颖性、创造性,其从属权利要求8也具备新颖性、创造性。</td><td>2</td></tr><tr><td>5、分案申请中权利要求的新颖性和创造性。</td><td></td><td></td></tr><tr><td>权利要求1与附件2、附件3分别对比,附件2、3均没有公开有关电机正反转的技术方案,因此权利要求1具备新颖性。</td><td>2</td><td rowspan="2">分别与附件2、附件3单独对比,以及结论具备新颖性,就可得分。</td></tr><tr><td>权利要求2与附件2、附件3分别对比,附件2、3均没有公开有关电机正反转的技术方案,因此权利要求2具备新颖性。</td><td>2</td></tr><tr><td>权利要求1、2的创造性</td><td></td><td></td></tr><tr><td>由于附件2、3中均没有公开食品料理机电机正反转的控制方式,也没有给出任何启示,而上述区别特征也不属于所属技术领域的惯用手段,</td><td>211</td><td>【区别特征】=2分</td></tr><tr><td>因此,分案申请中的独立权利要求1、2相对于对比文件附件2、3或者其结合具有突出的实质性特点和显著的进步,</td><td>1</td><td></td></tr><tr><td>具备专利法第22条第3款规定的创造性。</td><td>1</td><td></td></tr><tr><td>整体表述</td><td></td><td></td></tr><tr><td>逻辑通顺,表述简洁清楚,层次清楚</td><td>3</td><td></td></tr><tr><td>卷面整洁</td><td>2</td><td></td></tr></table>', 3474);
