INSERT OR REPLACE INTO reference_materials (id, source_file, chunk_index, content, tokens) VALUES ('ref_4b2b7768ba94', '专利代理实务真题2010.pdf', 61, '# 思博知网® MYSIPO

第二题评分标准 B（满分 55 分）

<table><tr><td>参考答案</td><td>分值</td><td>有关说明</td></tr><tr><td>一、简述审查指南中关于确定最接近的现有技术需要考虑的因素</td><td></td><td></td></tr><tr><td>最接近的现有技术,是指现有技术中与要求保护的发明最密切相关的一个技术方案,它是判断发明是否具有突出的实质性特点的基础。</td><td>2</td><td>[概念]=2分</td></tr><tr><td>最接近的现有技术,例如可以是,与要求保护的发明技术领域相同,所要解决的技术问题、技术效果或者用途最接近和/或公开了发明的技术特征最多的现有技术。</td><td>2</td><td></td></tr><tr><td>或者,虽然与要求保护的发明技术领域不同,但能够实现发明的功能,并且公开了发明的技术特征最多的现有技术。</td><td>1</td><td></td></tr><tr><td>应当注意的是,在确定最接近的现有技术时,应当首先考虑技术领域相同或相近似的现有技术。</td><td>2</td><td></td></tr><tr><td>二、确定附件2、附件3中哪一篇是本申请最接近的现有技术</td><td></td><td></td></tr><tr><td>附件2的技术领域与本申请相同,都是用于日常生活的食品加工领域,并且公开的特征也最多。附件3属于工业领域,技术领域与本申请不同,因此,附件2应为最接近的现有技术。</td><td>111</td><td>(1)附件编号错误,但从其答题内容的上下文可以看出对事实的认识是对的,正常得分。在整体表述部分酌情减分。</td></tr><tr><td>三、说明撰写的权利要求相对于现有技术具备新颖性和创造性的理由</td><td></td><td></td></tr><tr><td>1、权利要求1的新颖性</td><td></td><td></td></tr><tr><td>权利要求1与附件2相比:</td><td>2</td><td rowspan="3">[单独对比原则]=2分(1)只要提到附件2中没有公开权利要求1中的任何一</td></tr><tr><td>区别特征在于具有能够控制电机正反转的电路控制器件,</td><td>2</td></tr><tr><td>因此,权利要求1相对于附件2具备新颖性。</td><td>1</td></tr><tr><td></td><td></td><td>个技术特征即可得分;(2)区别技术特征认定最多给2分,[结论]=1分</td></tr><tr><td>权利要求1与附件3相比;</td><td>2</td><td rowspan="3">[单独对比原则]=2分(1)只要提到附件3中没有公开权利要求1中的任何一个技术特征即可得分;(2)区别技术特征认定最多给2分,[结论]=1分</td></tr><tr><td>区别特征在于具有能够控制电机正反转的电路控制器件,</td><td>2</td></tr><tr><td>因此,权利要求1相对于附件3具备新颖性。</td><td>1</td></tr><tr><td>2、权利要求1的创造性</td><td></td><td></td></tr><tr><td>权利要求1与最接近的现有技术附件2的区别在于:具有能够控制电机正反转的电路控制器件,</td><td>2</td><td rowspan="2">(2)区别特征中引流罩的形状表述成"为上下开口的中空筒状"亦可(3)[结论]</td></tr><tr><td>该特征解决的技术问题为使得浆料被撞击,摩擦得更充分,</td><td>1</td></tr><tr><td>附件2中既没有公开该技术特征也没有给出任何技术启示,无法解决上述技术问题。</td><td>2</td><td></td></tr><tr><td>而附件3所涉及的技术领域、解决的技术问题均与本申请完全不同</td><td>3</td><td></td></tr><tr><td>附件3公开的推进式搅拌器并未给出获得与“电机正反转”相关的上述区别特征的技术启示</td><td>1</td><td></td></tr><tr><td>而上述区别也不属于所属技术领域的惯用手段。</td><td>1</td><td></td></tr><tr><td rowspan="2">因此,权利要求1相对于附件2、3及其结合,具有突出的实质性特点和显著的进步,具备专利法第22条第3款规定的创造性。</td><td>1</td><td></td></tr><tr><td>1</td><td></td></tr><tr><td>3、从属权利要求2的新颖性、创造性</td><td></td><td></td></tr><tr><td>由于权利要求1具备新颖性,其从属权利要求2也具备新颖性.</td><td>1</td><td></td></tr><tr><td>由于权利要求1具备创造性,其从属权利要求2也具备创造性.</td><td>1</td><td></td></tr><tr><td>4、关于权利要求3、4的新颖性、创造性</td><td></td><td></td></tr><tr><td>区别技术特征“控制电机正反转”</td><td>1</td><td></td></tr><tr><td>新颖性单独对比</td><td>2</td><td></td></tr><tr><td>具备新颖性结论</td><td>1</td><td></td></tr><tr><td>附件2、3未公开区别技术特征××××</td><td>2</td><td></td></tr><tr><td>权利要求3具备创造性的结论</td><td>1</td><td></td></tr><tr><td>权利要求3具备新颖性、创造性,其从属权利要求4也具备新颖性、创造性。</td><td>1</td><td></td></tr><tr><td>5、分案的权利要求具备新颖性、创造性</td><td></td><td></td></tr><tr><td>权利要求1与附件2、附件3分别对比</td><td></td><td></td></tr><tr><td>附件2、附件3均没有公开有关引流罩的技术方案,因此权利要求1具备新颖性</td><td>2</td><td>分别与附件2、附件3对比,以及结论具备新颖性,即可得分</td></tr><tr><td>权利要求2与附件2、附件3分别对比</td><td></td><td></td></tr><tr><td>附件2、附件3均没有公开有关引流罩的技术方案,因此权利要求2具备新颖性</td><td>2</td><td></td></tr><tr><td>权利要求1、2的创造性</td><td></td><td></td></tr><tr><td>附件2、附件3均没有公开有关引流罩的技术方案。</td><td>2</td><td>[区别特征]=2分</td></tr><tr><td>也没有给出技术启示</td><td>1</td><td></td></tr><tr><td>而上述区别特征也不属于所属技术领域的惯用手段。</td><td>1</td><td></td></tr><tr><td>因此,分案申请中的独立权利要求1、2相对于对比文件附件2、3及其结合具有突出的实质性特点和显著的进步。</td><td>1</td><td></td></tr><tr><td>具备专利法第22条第3款规定的创造性。</td><td>1</td><td></td></tr><tr><td>整体表述</td><td></td><td></td></tr><tr><td>逻辑通顺</td><td>2</td><td></td></tr><tr><td>卷面整洁</td><td>1</td><td></td></tr></table>', 3399);
